import ProductGridSkeleton from "@/components/ProductGridSkeleton";

export default function ProductPageSkeleton() {
  return (
    <div className="product-page bg-[#f8f8f8]">
      <section className="product-summary px-4 pb-12 pt-6 sm:px-6 sm:pt-8 lg:px-8">
        <div className="gallery">
          <div className="grid gap-5 lg:grid-cols-[112px_minmax(0,1fr)] lg:items-start">
            <div className="order-2 hidden flex-col gap-3 lg:order-1 lg:flex">
              <div className="h-4 w-12 animate-pulse rounded bg-gray-100" />
              <div className="flex flex-col gap-3">
                {Array.from({ length: 4 }).map((_, index) => (
                  <div
                    key={`product-page-thumb-${index}`}
                    className="h-24 w-24 animate-pulse rounded-xl border border-gray-200 bg-white"
                  />
                ))}
              </div>
            </div>

            <section className="order-1">
              <div className="hidden overflow-hidden rounded-xl border border-gray-200 bg-white lg:block">
                <div className="aspect-square animate-pulse bg-gray-100" />
              </div>
              <div className="flex gap-3 overflow-hidden pb-2 lg:hidden">
                {Array.from({ length: 2 }).map((_, index) => (
                  <div
                    key={`product-page-mobile-${index}`}
                    className="aspect-square w-[82%] flex-shrink-0 animate-pulse rounded-xl border border-gray-200 bg-white"
                  />
                ))}
              </div>
            </section>
          </div>
        </div>

        <aside className="product-info">
          <div className="rounded-xl border border-gray-200 bg-white p-4 lg:sticky lg:top-24 lg:p-5">
            <div className="space-y-4">
              <div className="h-8 w-3/4 animate-pulse rounded bg-gray-100" />
              <div className="h-9 w-40 animate-pulse rounded bg-gray-100" />
              <div className="flex gap-2">
                <div className="h-6 w-24 animate-pulse rounded-full bg-gray-100" />
                <div className="h-6 w-28 animate-pulse rounded-full bg-gray-100" />
              </div>
              <div className="flex items-center gap-3">
                <div className="h-10 w-32 animate-pulse rounded-lg bg-gray-100" />
              </div>
              <div className="h-12 w-full animate-pulse rounded-lg bg-gray-100" />
              <div className="space-y-2">
                <div className="h-4 w-32 animate-pulse rounded bg-gray-100" />
                <div className="h-4 w-40 animate-pulse rounded bg-gray-100" />
              </div>
              <div className="space-y-2">
                <div className="h-4 w-full animate-pulse rounded bg-gray-100" />
                <div className="h-4 w-5/6 animate-pulse rounded bg-gray-100" />
                <div className="h-4 w-2/3 animate-pulse rounded bg-gray-100" />
              </div>
            </div>
          </div>
        </aside>
      </section>

      <div className="mx-auto w-full max-w-6xl px-4 pb-12 sm:px-6 lg:px-8">
        <section className="mt-5 flex flex-col gap-5 md:mt-8 md:gap-8">
          <div className="rounded-xl border border-gray-200 bg-white p-4 md:p-5">
            <div className="h-5 w-40 animate-pulse rounded bg-gray-100" />
            <div className="mt-4 grid gap-4 sm:grid-cols-2">
              {Array.from({ length: 4 }).map((_, index) => (
                <div key={`product-page-spec-${index}`} className="space-y-2">
                  <div className="h-3 w-20 animate-pulse rounded bg-gray-100" />
                  <div className="h-4 w-32 animate-pulse rounded bg-gray-100" />
                </div>
              ))}
            </div>
          </div>

          <div className="rounded-xl border border-gray-200 bg-white p-4 md:p-5">
            <div className="h-6 w-48 animate-pulse rounded bg-gray-100" />
            <div className="mt-4 space-y-3">
              {Array.from({ length: 5 }).map((_, index) => (
                <div key={`product-page-row-${index}`} className="flex flex-col gap-2 sm:flex-row sm:items-start sm:gap-4">
                  <div className="h-4 w-28 animate-pulse rounded bg-gray-100" />
                  <div className="h-4 w-40 animate-pulse rounded bg-gray-100" />
                </div>
              ))}
            </div>
          </div>
        </section>

        <section className="mt-8 md:mt-10">
          <div className="mb-4 h-6 w-40 animate-pulse rounded bg-gray-100" />
          <ProductGridSkeleton count={4} />
        </section>
      </div>
    </div>
  );
}
